var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"영속의 세월과 견주기에 인간의 삶은 짧다.","JPN":"永続的な月日と比べるには、人間の人生は短い。","ENG":"Human life is short compared to the eternal time.","TWN":"與永恆的歲月相比，人類的生命是短暫的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇기에 인간은 어리석음과 죄악을 반복한다.","JPN":"そのため人間は愚かな罪を繰り返す。","ENG":"That is why humans repeat foolishness and sin.","TWN":"正因為如此，人類才會重複愚蠢和罪惡。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"영원한 선인도, 영원한 악인도 없다.","JPN":"永遠の善人も、永遠の悪人もいない。","ENG":"There is no absolute good or evil.","TWN":"沒有永遠的善人，也沒有永遠的惡人。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 기억하기로 했던 이름이 한 반역자의 칼날에 스러졌을 때…","JPN":"アタシが記憶に刻んだ名前が、ある反逆者の刃により消えた時……","ENG":"When the name I chose to remember fell to the blade of the traitor...","TWN":"當我記住的那個名字在一個叛徒的刀下消逝時…"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 그 순환이 지긋지긋하다고 생각했다.","JPN":"アタシはその循環にうんざりした。","ENG":"I got sick of this cycle.","TWN":"我覺得這種迴圈真是令人厭倦。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ffd34c>반역자에게 죽은 아발론의 옛왕이 훗날 동토에서 다시 태어나 그루터기를 이끌리라.</color>","JPN":" <color=#ffd34c>反逆者に殺されたアバロンの昔の王が近い将来、凍土で生まれ変わり、切り株を導くであろう。</color>","ENG":"<color=#ffd34c>The old king of Avalon, slain by the traitor, will be reborn in the gelid lands and lead the Stump.</color>","TWN":"<color=#ffd34c>被叛徒殺死的阿瓦隆舊王將會在凍土中重生，並帶領木墩。</color>"},"stage":{"bg":"ROOT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ffd34c>뿔을 갖고 태어난 그녀는 자신이 사랑한 고향을 지켜내고, 그루터기의 악마에게 심장을 잃을지니.</color>","JPN":" <color=#ffd34c>ツノを持って生まれた彼女は、自分が愛した故郷を守り抜き、切り株の悪魔によって心臓を失うであろう。</color>","ENG":"<color=#ffd34c>The girl born with a horn will protect her home, and she will lose her heart to the devil of the Stump.</color>","TWN":"<color=#ffd34c>她將帶著角出生，守護她所愛的故鄉，最後被木墩的魔鬼奪走心臟。</color>"},"stage":{"bg":"ROOT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"황금나무가 마지막으로 속삭여준 그 이야기만이… 지금껏 날 지탱해온, 유일한 희망이었다.","JPN":"黄金の木が最後にささやいたあの言葉だけが……今までアタシを支えてくれた、唯一の希望だった。","ENG":"The last whisper of the Golden Tree... was the sole hope that sustained me until now.","TWN":"黃金樹最後的低語…一直以來是支撐著我的唯一希望。"},"stage":{"bg":"ROOT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그 이름을 부를 순 없더라도… 다시 한 번…","JPN":"その名前を呼ぶことができなくても……もう一度……","ENG":"Even though I cannot call out that name... just once more...","TWN":"就算不能再一次呼喚那個名字…"},"stage":{"bg":"ROOT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"널 만나고 싶었다.","JPN":"アナタに会いたい。","ENG":"I wished to meet you again.","TWN":"我也想見到你。"},"stage":{"bg":"ROOT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"이번에야말로, 널 지켜내고 싶다.","JPN":"今度こそ、アナタを守りたい。","ENG":"This time, I wish to protect you.","TWN":"這次，我會守護你。"},"stage":{"bg":"ROOT_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"황금나무가 속삭인 미래를… 바꾸어서라도.","JPN":"黄金の木がささやいた未来を……変えてでも。","ENG":"Even if that means... changing the future whispered by the Golden Tree.","TWN":"就算是要改變黃金樹低語的未來…"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아프네.","JPN":"痛いわね。","ENG":"It stings.","TWN":"還蠻痛的。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하마터면 정신 놓을 뻔했어.","JPN":"危うく気を失うところだったわ。","ENG":"I almost lost my mind.","TWN":"差點失去意識了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"끈질기군.","JPN":"しつこいぞ。","ENG":"How persistent you are.","TWN":"真是頑強。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그게 내 특기란다.","JPN":"それがアタシの特技よ。","ENG":"That is my specialty.","TWN":"那是我的專長。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"나를 이겨보겠다는 듯이 도발하더니…","JPN":"余に勝つとばかりに挑発しておいて……","ENG":"You taunt me as if you wish to defeat me...","TWN":"你好像要打敗我似的挑釁我…"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"공격을 피해 도망만 치는 게 전부인가?","JPN":"逃げ回るのが、精一杯か？","ENG":"Yet, is avoiding my attacks and running away all you can do?","TWN":"結果卻只是躲避攻擊逃跑嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"후훗.","JPN":"ふふっ。","ENG":"Fu fuu.","TWN":"呵呵。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너야말로, 너무 날 노리는데만 정신이 팔려 있지 않아?","JPN":"アナタこそ、アタシを狙うことに夢中になってない？","ENG":"What about you? Do you not think that you are too preoccupied in trying to defeat me?","TWN":"你才是，太專注於盯著我看了吧？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이건…? 나무뿌리?","JPN":"これは……？　木の根？","ENG":"Is this... a tree root?","TWN":"這是…？樹根？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내가 공격하는 틈에 발밑을 노렸군.","JPN":"余が攻撃している間に足元を狙ったのか。","ENG":"So you targeted my feet whilst I was attacking you.","TWN":"趁我攻擊的空隙瞄準了我的腳下嗎。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};